import { inngest } from "../client";

export const userOnboarding = inngest.createFunction(
  {
    id: "user-onboarding",
    retries: { attempts: 3 },
    triggers: [{ event: "app/user.created" }],
  },
  async ({ event, step }) => {
    const profile = await step.run("create-profile", async () => ({
      userId: event.data.userId,
      email: event.data.email,
    }));

    await step.run("send-welcome-email", async () => {
      console.log("send welcome email", profile.email);
    });

    return { ok: true, userId: profile.userId };
  }
);

import { serve } from "inngest/next";

import { inngest } from "@/inngest/client";
import { userOnboarding } from "@/inngest/functions/user-onboarding";

export const { GET, POST, PUT } = serve({
  client: inngest,
  functions: [userOnboarding],
});

const checks = [
  "Install vendor package and configure env",
  "Run the local example path",
  "Add auth, retries, and audit events before production",
];

export default function InngestFunctionsPage() {
  return (
    <main className="flex flex-col gap-6 p-6">
      <div>
        <h1 className="text-2xl font-semibold">Inngest Functions</h1>
        <p className="text-muted-foreground">Durable event-driven functions with steps, retries, and scheduled work.</p>
      </div>
      <div className="grid gap-3">
        {checks.map((check) => (
          <div key={check} className="rounded-lg border p-4 text-sm">{check}</div>
        ))}
      </div>
    </main>
  );
}
